function tree(scale=1){const g=new THREE.Group(),trunk=new THREE.Mesh(new THREE.CylinderGeometry(.07*scale,.1*scale,.52*scale,6),new THREE.MeshStandardMaterial({color:0x5a3822,roughness:.9})),leaves=new THREE.Mesh(new THREE.ConeGeometry(.32*scale,.72*scale,7),new THREE.MeshStandardMaterial({color:0x31573a,roughness:.85}));trunk.position.y=.24*scale;leaves.position.y=.68*scale;g.add(trunk,leaves);g.traverse(o=>o.castShadow=true);return g}
