function addObstacle(obstacle){const {type,x,y}=obstacle,tile=terrainTile(x,y);if(!tile)return;tile.userData.terrain=type;if(type==='river'){tile.material.color.setHex(0x356b82);const water=new THREE.Mesh(new THREE.BoxGeometry(.86,.035,.86),new THREE.MeshStandardMaterial({color:0x3e83a0,metalness:.25,roughness:.25}));water.position.set(x-2.5,.005,y-2.5);board.add(water)}if(type==='bridge'){tile.material.color.setHex(0x76502e);for(let i=-.26;i<=.26;i+=.26){const plank=new THREE.Mesh(new THREE.BoxGeometry(.7,.05,.11),new THREE.MeshStandardMaterial({color:0x8e6238,roughness:.85}));plank.position.set(x-2.5,.02,y-2.5+i);board.add(plank)}}if(type==='tree'){const model=tree(.82);model.position.set(x-2.5,0,y-2.5);board.add(model)}if(type==='rock'){const rock=new THREE.Mesh(new THREE.DodecahedronGeometry(.31,0),new THREE.MeshStandardMaterial({color:0x60645c,roughness:1}));rock.position.set(x-2.5,.23,y-2.5);rock.scale.set(1.15,.8,1);rock.castShadow=true;board.add(rock)}if(type==='bramble'){tile.material.color.setHex(0x765c31);for(let i=-.18;i<=.18;i+=.18){const thorn=new THREE.Mesh(new THREE.ConeGeometry(.07,.28,5),new THREE.MeshStandardMaterial({color:0x8f7a39,roughness:.9}));thorn.position.set(x-2.5+i,.12,y-2.5+(i===0 ? .12 : -.1));board.add(thorn)}}if(type==='shrine'){tile.material.color.setHex(0x625b88);const base=new THREE.Mesh(new THREE.CylinderGeometry(.22,.29,.1,8),new THREE.MeshStandardMaterial({color:0x8f82c5,metalness:.5,roughness:.3})),crystal=new THREE.Mesh(new THREE.OctahedronGeometry(.15),new THREE.MeshStandardMaterial({color:0xaedbff,emissive:0x3b74a0,emissiveIntensity:1.4,roughness:.2}));base.position.set(x-2.5,.04,y-2.5);crystal.position.set(x-2.5,.27,y-2.5);base.userData.cell=crystal.userData.cell={x,y};board.add(base,crystal);obstacle.crystal=crystal}}
function missionBackdrop(){scenery.clear();if(missionIndex===0){[-4.6,4.6].forEach(x=>torch(x,-3.4))}if(missionIndex===1){const water=new THREE.Mesh(new THREE.BoxGeometry(8,.05,1.2),new THREE.MeshStandardMaterial({color:0x356b82,metalness:.2,roughness:.35}));water.position.set(0,-.18,-3.6);scenery.add(water);for(let x=-2.4;x<=2.4;x+=.6){const plank=new THREE.Mesh(new THREE.BoxGeometry(.5,.12,1.1),new THREE.MeshStandardMaterial({color:0x855a34,roughness:.85}));plank.position.set(x,.02,-3.6);scenery.add(plank)}}if(missionIndex===2){[[-3.6,-2.5],[-3.5,-.8],[-2.9,-3.7],[3.4,-3.2],[3.7,-1.5]].forEach(([x,z])=>{const t=tree(1.25);t.position.set(x,0,z);scenery.add(t)})}if(missionIndex===3){[[-3.8,-3.7],[-1.5,-4.1],[1,-3.8],[3.4,-3.5]].forEach(([x,z],i)=>{const hill=new THREE.Mesh(new THREE.ConeGeometry(.85+i*.12,1.25+i*.14,7),new THREE.MeshStandardMaterial({color:0x56614c,roughness:1}));hill.position.set(x,.55,z);hill.castShadow=true;scenery.add(hill)})}if(missionIndex===4){const wall=new THREE.Mesh(new THREE.BoxGeometry(6.5,1.2,.35),new THREE.MeshStandardMaterial({color:0x55554c,roughness:1}));wall.position.set(0,.5,-3.8);scenery.add(wall);[-2.6,2.6].forEach(x=>{const tower=new THREE.Mesh(new THREE.CylinderGeometry(.42,.48,1.8,6),new THREE.MeshStandardMaterial({color:0x66645b,roughness:1}));tower.position.set(x,.85,-3.75);scenery.add(tower)})}}
function dioramaRock(x,z,scale=.5){const rock=new THREE.Mesh(new THREE.DodecahedronGeometry(scale,0),new THREE.MeshStandardMaterial({color:0x41483d,roughness:1}));rock.position.set(x,scale*.55,z);rock.scale.set(1.3,.75,1);rock.castShadow=true;scenery.add(rock)}
function torch(x,z){const g=new THREE.Group(),post=new THREE.Mesh(new THREE.CylinderGeometry(.045,.055,.7,6),new THREE.MeshStandardMaterial({color:0x4b3424,roughness:.8})),flame=new THREE.Mesh(new THREE.ConeGeometry(.11,.28,6),new THREE.MeshStandardMaterial({color:0xffb34f,emissive:0xb84d12,emissiveIntensity:1.6,roughness:.3}));post.position.y=.35;flame.position.y=.8;g.add(post,flame);g.position.set(x,0,z);scenery.add(g);ambience.push({mesh:flame,baseY:.8,phase:x+z,kind:'flame'})}
function addAtmosphere(color,count,kind='mist'){const ring=[[-4,-2.8],[-3.8,.8],[-2,-4.4],[.4,-4.5],[2.7,-4.1],[4,-2.1],[3.8,.8]];for(let i=0;i<count;i++){const [x,z]=ring[i%ring.length],orb=new THREE.Mesh(new THREE.SphereGeometry(kind==='mist' ? .48:.045,8,6),new THREE.MeshBasicMaterial({color,transparent:true,opacity:kind==='mist' ? .08:.78,depthWrite:false}));orb.position.set(x,(kind==='mist' ? .32:.3)+(i%2)*.14,z);scenery.add(orb);ambience.push({mesh:orb,baseX:orb.position.x,baseY:orb.position.y,phase:i*1.7,kind})}}
function roundBattlefield(){const paint=document.createElement('canvas');paint.width=paint.height=512;const ctx=paint.getContext('2d'),gradient=ctx.createRadialGradient(256,256,70,256,256,256);gradient.addColorStop(0,'rgba(103,121,82,.92)');gradient.addColorStop(.48,'rgba(66,81,58,.72)');gradient.addColorStop(.78,'rgba(41,51,41,.34)');gradient.addColorStop(1,'rgba(21,25,23,0)');ctx.fillStyle=gradient;ctx.fillRect(0,0,512,512);const aura=new THREE.Mesh(new THREE.CircleGeometry(6.25,64),new THREE.MeshBasicMaterial({map:new THREE.CanvasTexture(paint),transparent:true,depthWrite:false})),rim=new THREE.Mesh(new THREE.RingGeometry(6.08,6.25,64),new THREE.MeshBasicMaterial({color:0x77764d,transparent:true,opacity:.28,depthWrite:false}));aura.rotation.x=rim.rotation.x=-Math.PI/2;aura.position.y=-.155;rim.position.y=-.15;scenery.add(aura,rim)}
function backgroundForMission(){ambience=[];missionBackdrop();roundBattlefield();if(missionIndex===0){addAtmosphere(0xb9d5dc,5)}if(missionIndex===1){[[-4,-3.5],[3.8,-3.2],[-3.6,.9]].forEach(([x,z])=>dioramaRock(x,z,.6));torch(-5,-2.7);torch(4.9,-2.5);addAtmosphere(0xb9d5dc,6)}if(missionIndex===2){[[-4,-3.8],[-3.9,2.5],[4,-3.8]].forEach(([x,z])=>{const t=tree(1.5);t.position.set(x,0,z);scenery.add(t)});addAtmosphere(0xd0ddca,7)}if(missionIndex===3){[[-4,-3.5],[-2.5,2.9],[3.8,-3.2]].forEach(([x,z])=>dioramaRock(x,z,.8));addAtmosphere(0xbfc5af,5)}if(missionIndex===4){[-3.4,3.4].forEach(x=>torch(x,-3.25));[[-4,-3.7],[4,-3.8],[-3.8,1.5]].forEach(([x,z])=>dioramaRock(x,z,.65));addAtmosphere(0xff8c4b,12,'ember')}}
function setup(){board.clear();scenery.clear();units=[];obstacles=[];selected=null;hoveredTile=null;phase='player';tutorialStep=0;battleBusy=false;ui.log.innerHTML='';ui.modal.classList.add('hidden');ui.battle.classList.add('hidden');ui.endTurn.classList.remove('tutorial-target');ui.endTurnMobile.classList.remove('tutorial-target');const m=missions[missionIndex];ui.mission.textContent=m.code||`MISSION 0${missionIndex+1}`;ui.missionSelect.value=missionIndex;ui.mobileMissionSelect.value=missionIndex;ui.objective.textContent=m.objective;for(let x=0;x<6;x++)for(let y=0;y<6;y++){const t=new THREE.Mesh(new THREE.BoxGeometry(.94,.12,.94),new THREE.MeshStandardMaterial({color:(x+y)%2?0x66735a:0x798166,roughness:1}));t.position.set(x-2.5,-.08,y-2.5);t.receiveShadow=true;t.userData={tile:true,x,y};board.add(t)}obstacles=(m.obstacles||[]).map(([type,x,y])=>({type,x,y,used:false}));obstacles.forEach(addObstacle);backgroundForMission();m.players.forEach(([n,t,x,y])=>units.push(makeUnit(n,t,x,y,'player')));m.enemies.forEach(([n,t,x,y,h])=>{const unit=makeUnit(n,t,x,y,'enemy',h||10);unit.armor=n==='IRON CAPTAIN'?2:0;unit.enraged=false;units.push(unit)});log(m.tutorial?'Training field ready. Follow the field drill card.':'Your force reaches the field.');renderTutorial();updateUI();hint(m.tutorial?'Start the drill: select a blue unit.':'Select a blue unit.')}
function updateUI(){if(!selected||!alive(selected)){ui.name.textContent='—';ui.cls.textContent=ui.move.textContent=ui.range.textContent=ui.moveAction.textContent=ui.attackAction.textContent=ui.hp.textContent='—';ui.bar.style.width='0';return}const c=classes[selected.type],label=selected.team==='player'?'ALLY':'ENEMY';ui.name.innerHTML=`${selected.name} <span class="unit-team ${selected.team}">(${label})</span>`;ui.cls.textContent=selected.type.toUpperCase();ui.move.textContent=c.move;ui.range.textContent=c.range;ui.moveAction.textContent=selected.team==='player'?(selected.moved?'USED':'READY'):'—';ui.attackAction.textContent=selected.team==='player'?(selected.acted?'USED':'READY'):'—';ui.hp.textContent=`${Math.max(0,selected.hp)}/${selected.maxHp}`;ui.bar.style.width=`${Math.max(0,selected.hp)/selected.maxHp*100}%`}
async function moveUnit(unit,x,y){const from=unit.mesh.position.clone(),to=new THREE.Vector3(x-2.5,0,y-2.5);await tween(360,p=>{const eased=p<.5?2*p*p:1-Math.pow(-2*p+2,2)/2,wobble=Math.sin(p*Math.PI*4)*(1-p);unit.mesh.position.lerpVectors(from,to,eased);unit.mesh.position.y=Math.sin(p*Math.PI)*.12;unit.mesh.rotation.z=wobble*.16});unit.mesh.position.copy(to);unit.mesh.rotation.set(0,0,0);unit.x=x;unit.y=y}
function removeUnit(unit){board.remove(unit.mesh);units=units.filter(u=>u!==unit);if(selected===unit)selected=null}
function applyTerrainEffects(unit){const tile=obstacles.find(o=>o.x===unit.x&&o.y===unit.y);if(!tile)return false;if(tile.type==='shrine'&&unit.team==='player'){const healing=Math.min(4,unit.maxHp-unit.hp);if(healing){unit.hp+=healing;sfx('shrine');log(`${nameTag(unit)} restores ${healing} HP at the healing shrine.`);tutorialAdvance('heal');updateUI()}}if(tile.type==='bramble'){unit.hp-=1;sfx('trap');log(`${nameTag(unit)} takes 1 damage from the brambles.`);tutorialAdvance('trap');if(unit.hp<=0){sfx('death');log(`${nameTag(unit)} falls.`);removeUnit(unit);updateUI();return checkEnd()}}return false}
function clearTiles(){board.children.filter(o=>o.userData.tile).forEach(t=>t.material.color.setHex(t.userData.terrain==='river'?0x356b82:t.userData.terrain==='bridge'?0x76502e:t.userData.terrain==='bramble'?0x765c31:t.userData.terrain==='shrine'?0x625b88:(t.userData.x+t.userData.y)%2?0x66735a:0x798166))}function selectionRing(unit,color=0x76d4e5){if(unit.selectionRing){unit.selectionRing.material.color.setHex(color);return unit.selectionRing}const ring=new THREE.Mesh(new THREE.RingGeometry(.36,.44,24),new THREE.MeshBasicMaterial({color,transparent:true,opacity:.95,side:THREE.DoubleSide,depthWrite:false}));ring.rotation.x=-Math.PI/2;ring.position.y=.005;ring.visible=false;unit.mesh.add(ring);unit.selectionRing=ring;return ring}function resetEmissive(){units.forEach(u=>{u.mesh.children[0].material.emissive.setHex(0);if(u.selectionRing)u.selectionRing.visible=false})}function flashAction(unit,action=unit.moved?'move':'attack'){if(unit.team!=='player')return;const label=ui[action==='attack'?'attackAction':'moveAction'];label.classList.remove('action-warning');void label.offsetWidth;label.classList.add('action-warning');setTimeout(()=>label.classList.remove('action-warning'),850)}function paintSelection(){clearTiles();resetEmissive();if(!selected||!alive(selected))return;if(selected.team==='enemy'){selectionRing(selected,0xe27166).visible=true;return}selectionRing(selected,0x76d4e5).visible=true;const move=classes[selected.type].move,guide=tutorialGuideTile(),strict=tutorialActive(),available=!privateMode||phase==='player';board.children.filter(o=>{const d=walkDistance(selected,o.userData.x,o.userData.y);if(d&&d<=move&&!selected.moved&&!selected.acted&&available)o.material.color.setHex(0x3e7d91)});if(strict&&guide)guide.material.color.setHex(0xc59b4b);if(available)units.filter(e=>e.team==='enemy'&&canAttack(selected,e)&&!selected.acted).forEach(e=>e.mesh.children[0].material.emissive.setHex(0x882222))}function privatePrompt(){if(!privateMatch)return 'Private battle.';return privateMatch.state.winner?'The battle is finished.':privateMatch.state.turn===privateMatch.side?'Your turn. Select a blue troop.':"Your rival's turn. You may inspect any troop."}function deselect(){selected=null;hoveredTile=null;clearTiles();resetEmissive();updateUI();hint(privateMode?privatePrompt():tutorialActive()?tutorialPrompt():'Select a blue unit.')}
function select(unit){const required=tutorialActive()&&unit.team==='player'?tutorialUnit():null;if(required&&unit.name!==required&&!(unit.moved&&unit.acted)){tutorialReject();return}selected=unit;hoveredTile=null;paintSelection();if(unit.team==='enemy'){tutorialAdvance('inspect');hint(privateMode?privatePrompt():`${unit.name} is an enemy. Its class and HP are shown in the panel.`);sfx('select')}else{tutorialAdvance('select');hint(privateMode?privatePrompt():tutorialActive()?tutorialPrompt():unit.acted?'This unit has acted. Choose another unit.':unit.moved?'Choose an enemy in range.':'Choose a blue tile to move, or a red enemy to attack.');sfx('select')}updateTutorialMarker();updateUI()}
function weaponMark(type){return `<span class="weapon-mark weapon-${type}" aria-label="${type}"><i></i><b></b></span>`}
function fighter(unit,role){const c=classes[unit.type];return `<span class="fighter-label">${role}</span><span style="color:#${c.color.toString(16).padStart(6,'0')}">${weaponMark(unit.type)}</span><strong>${unit.name}</strong><small>${unit.type.toUpperCase()} · ${Math.max(0,unit.hp)}/${unit.maxHp} HP</small>`}
function dismissBattle(){if(!closeBattle)return;sfx('click');ui.battle.classList.add('hidden');battleBusy=false;const resolve=closeBattle;closeBattle=null;resolve()}
function battleScene(a,b,dealt,counter){battleBusy=true;ui.attacker.innerHTML=fighter(a,'ATTACKER');ui.defender.innerHTML=fighter(b,'DEFENDER');ui.result.innerHTML=`<span>${a.name} deals <b>${dealt}</b> damage</span><span>${counter?`${b.name} counters for <b>${counter}</b>`:`${b.name} cannot counter`}</span>`;ui.battle.classList.remove('hidden');return new Promise(resolve=>{closeBattle=resolve})}
function tween(duration,draw){return new Promise(resolve=>{const start=performance.now();function frame(now){const p=Math.min(1,(now-start)/duration);draw(p);if(p<1)requestAnimationFrame(frame);else resolve()}requestAnimationFrame(frame)})}
async function boardStrike(source,target,color){const from=source.mesh.position.clone(),to=target.mesh.position.clone(),direction=to.clone().sub(from).setY(0).normalize(),targetStart=target.mesh.position.clone(),body=target.mesh.children[0].material;await tween(260,p=>{const arc=Math.sin(p*Math.PI);source.mesh.position.copy(from).addScaledVector(direction,.48*arc);source.mesh.position.y=.13*arc;source.mesh.rotation.z=(direction.x>=0?-1:1)*.3*arc;target.mesh.position.copy(targetStart);target.mesh.position.x+=Math.sin(p*Math.PI*3)*.045*arc;target.mesh.position.y=.08*arc;body.emissive.setHex(p>.32?color:0)});source.mesh.position.copy(from);source.mesh.rotation.set(0,0,0);target.mesh.position.copy(targetStart);body.emissive.setHex(0)}
async function arrowShot(source,target,color){const start=source.mesh.position.clone().add(new THREE.Vector3(.22,.82,.12)),end=target.mesh.position.clone().add(new THREE.Vector3(0,.65,0)),direction=end.clone().sub(start).normalize(),arrow=new THREE.Group(),shaft=new THREE.Mesh(new THREE.CylinderGeometry(.025,.025,.72,5),new THREE.MeshStandardMaterial({color:0x6d4529,roughness:.85})),tip=new THREE.Mesh(new THREE.ConeGeometry(.07,.18,4),new THREE.MeshStandardMaterial({color:0xd8d8d1,metalness:.6,roughness:.3})),body=target.mesh.children[0].material;tip.position.y=.45;arrow.add(shaft,tip);arrow.position.copy(start);arrow.quaternion.setFromUnitVectors(new THREE.Vector3(0,1,0),direction);board.add(arrow);await tween(360,p=>{arrow.position.lerpVectors(start,end,p);arrow.position.y+=Math.sin(Math.PI*p)*.48;body.emissive.setHex(p>.88?color:0)});board.remove(arrow);body.emissive.setHex(0)}
async function animateBattle(a,b,counter){if(a.type==='bow')await arrowShot(a,b,0x9f302b);else await boardStrike(a,b,0x9f302b);if(counter&&alive(a)&&alive(b)){await wait(70);if(b.type==='bow')await arrowShot(b,a,0x2c6170);else await boardStrike(b,a,0x2c6170)}}
async function attack(a,b){if(!alive(a)||!alive(b))return false;const rage=a.name==='IRON CAPTAIN'&&a.enraged?2:0,armor=b.armor||0,cover=coverBonus(b),base=advantage(a.type,b.type)?4:advantage(b.type,a.type)?2:3,archerWeakness=b.type==='bow'&&a.type!=='bow'?1:0,dealt=Math.max(1,base+rage+archerWeakness-cover-armor),counterBase=canAttack(b,a)?(advantage(b.type,a.type)?3:advantage(a.type,b.type)?1:2)+(b.name==='IRON CAPTAIN'&&b.enraged?2:0):0,counter=counterBase?Math.max(1,counterBase-coverBonus(a)):0;await battleScene(a,b,dealt,counter);battleBusy=true;await animateBattle(a,b,counter);if(armor){b.armor=0;log(`${nameTag(b)}'s iron armor absorbs ${armor} damage.`)}if(cover)log(`${nameTag(b)} uses cover to reduce the strike.`);b.hp-=dealt;sfx('attack');log(`${nameTag(a)} strikes ${nameTag(b)} for ${dealt}.`);if(b.hp<=0){sfx('death');log(`${nameTag(b)} falls.`);removeUnit(b)}else{if(b.name==='IRON CAPTAIN'&&!b.enraged&&b.hp<=b.maxHp/2){b.enraged=true;b.mesh.children[0].material.color.setHex(0x722b2a);log(`${nameTag(b)} enters RAGE PHASE — attacks deal +2 damage!`)}if(counter&&alive(a)){a.hp-=counter;sfx('counter');log(`${nameTag(b)} counters ${nameTag(a)} for ${counter}.`);if(a.hp<=0){sfx('death');log(`${nameTag(a)} falls.`);removeUnit(a)}}}resetEmissive();updateUI();battleBusy=false;return checkEnd()}
function checkEnd(){const mission=missions[missionIndex];if(!units.some(u=>u.team==='enemy')){phase='done';sfx('victory');setTimeout(()=>showModal('MISSION COMPLETE',mission.boss?'THE PATH IS YOURS':mission.tutorial?'FIELD DRILL COMPLETE':'The road opens ahead.',mission.boss?'You broke the captain’s line. The valley is safe.':mission.tutorial?'You have completed the field drill. Mission 01 is ready.':'No speeches. The company marches on.',mission.boss?'PLAY AGAIN':'NEXT MISSION'),200);return true}if(!units.some(u=>u.team==='player')){phase='done';sfx('gameover');setTimeout(()=>showModal('GAME OVER','THE COMPANY HAS FALLEN','All of your troops were defeated. Return to the start of this battle.','RETRY MISSION'),200);return true}return false}function showModal(k,t,c,b){ui.kicker.textContent=k;ui.title.textContent=t;ui.copy.textContent=c;ui.modalButton.textContent=b||'CONTINUE';ui.modal.classList.remove('hidden')}

function buildPrivateBoard(match){board.clear();scenery.clear();units=[];obstacles=[];selected=null;hoveredTile=null;tutorialStep=0;battleBusy=false;privateMatch=match;ui.log.innerHTML='';ui.modal.classList.add('hidden');delete ui.modal.dataset.privateShown;ui.battle.classList.add('hidden');ui.tutorial.classList.add('hidden');ui.endTurn.classList.remove('tutorial-target');ui.endTurnMobile.classList.remove('tutorial-target');ui.mission.textContent=`PRIVATE BATTLE · ${match.code}`;ui.objective.textContent='Hold the line. Break your rival’s force.';ui.missionSelect.disabled=true;ui.mobileMissionSelect.disabled=true;for(let x=0;x<6;x++)for(let y=0;y<6;y++){const tile=new THREE.Mesh(new THREE.BoxGeometry(.94,.12,.94),new THREE.MeshStandardMaterial({color:(x+y)%2?0x66735a:0x798166,roughness:1}));tile.position.set(x-2.5,-.08,y-2.5);tile.receiveShadow=true;tile.userData={tile:true,x,y};board.add(tile)}obstacles=match.state.obstacles.map(o=>({...o,used:false}));obstacles.forEach(addObstacle);backgroundForMission();match.state.units.forEach(data=>{const team=data.side===match.side?'player':'enemy',unit=makeUnit(data.name,data.type,data.x,data.y,team,data.maxHp);unit.hp=data.hp;unit.maxHp=data.maxHp;unit.moved=data.moved;unit.acted=data.acted;unit.onlineId=data.id;unit.onlineSide=data.side;units.push(unit)});phase=match.state.winner?'done':match.state.turn===match.side?'player':'enemy';ui.endTurn.disabled=ui.endTurnMobile.disabled=phase!=='player';log('Private armies take the field.');log(match.side==='host'?'You raised the blue banner and take the first turn.':'You joined beneath the blue banner. Your rival moves first.');updateUI();hint(privatePrompt())}

function reconcilePrivateState(match){privateMatch=match;const stateById=new Map(match.state.units.map(data=>[data.id,data]));for(const unit of [...units])if(!stateById.has(unit.onlineId))removeUnit(unit);for(const data of match.state.units){let unit=units.find(candidate=>candidate.onlineId===data.id);if(!unit){const team=data.side===match.side?'player':'enemy';unit=makeUnit(data.name,data.type,data.x,data.y,team,data.maxHp);unit.onlineId=data.id;unit.onlineSide=data.side;units.push(unit)}unit.hp=data.hp;unit.maxHp=data.maxHp;unit.moved=data.moved;unit.acted=data.acted;unit.x=data.x;unit.y=data.y;unit.mesh.position.set(data.x-2.5,0,data.y-2.5)}phase=match.state.winner?'done':match.state.turn===match.side?'player':'enemy';ui.objective.textContent=match.state.winner?'THE BATTLE IS DECIDED':`${phase==='player'?'YOUR TURN':'RIVAL’S TURN'} · ROUND ${match.state.round}`;ui.endTurn.disabled=ui.endTurnMobile.disabled=phase!=='player';if(selected&&!alive(selected))selected=null;updateUI();paintSelection();hint(privatePrompt())}

async function syncPrivateMatch(match){if(!privateMode)return;if(privateApplying){privateQueuedMatch=match;return}privateApplying=true;battleBusy=true;const event=match.lastEvent||{};try{if(event.type==='move'){const unit=units.find(candidate=>candidate.onlineId===event.unitId);if(unit){await moveUnit(unit,event.to.x,event.to.y);sfx('move');log(`${nameTag(unit)} advances to a new position.`);if(event.terrain?.type==='shrine'){sfx('shrine');log(`${nameTag(unit)} restores ${event.terrain.amount} HP at the healing shrine.`)}if(event.terrain?.type==='bramble'){sfx('trap');log(`${nameTag(unit)} takes ${event.terrain.amount} damage from the brambles.`);if(!match.state.units.some(data=>data.id===event.unitId)){sfx('death');log(`${nameTag(unit)} falls.`)}}}}if(event.type==='attack'){const attacker=units.find(unit=>unit.onlineId===event.attackerId),defender=units.find(unit=>unit.onlineId===event.targetId);if(attacker&&defender){await battleScene(attacker,defender,event.dealt,event.counter);battleBusy=true;await animateBattle(attacker,defender,event.counter);sfx('attack');log(`${nameTag(attacker)} strikes ${nameTag(defender)} for ${event.dealt}.`);if(event.defenderFell){sfx('death');log(`${nameTag(defender)} falls.`)}else if(event.counter){sfx('counter');log(`${nameTag(defender)} counters ${nameTag(attacker)} for ${event.counter}.`);if(event.attackerFell){sfx('death');log(`${nameTag(attacker)} falls.`)}}}}if(event.type==='end_turn')log(event.next===match.side?'— YOUR TURN —':'— RIVAL’S TURN —');if(event.type==='left')log('Your rival has withdrawn from the field.');reconcilePrivateState(match);if(match.state.winner&&!ui.modal.dataset.privateShown){ui.modal.dataset.privateShown='true';ui.modalButton.dataset.private='true';const won=match.state.winner===match.side;sfx(won?'victory':'gameover');showModal(won?'VICTORY':'DEFEAT',won?'YOUR BANNER STILL FLIES':'YOUR LINE HAS BROKEN',won?'Your rival’s force has been defeated.':'Your last troop has fallen.','RETURN TO WAR TABLE')}}finally{battleBusy=false;privateApplying=false;const queued=privateQueuedMatch;privateQueuedMatch=null;if(queued&&queued.version>match.version)setTimeout(()=>syncPrivateMatch(queued),0)}}

async function handlePrivatePointer(hits){let object=hits[0]?.object;while(object?.parent&&object.parent!==board)object=object.parent;const unit=units.find(candidate=>candidate.mesh===object),tile=tileFromHits(hits);if(unit){if(unit.team==='player'){if(unit===selected&&!unit.acted){deselect();return}select(unit);return}if(phase==='player'&&selected?.team==='player'&&!selected.acted&&canAttack(selected,unit)){battleBusy=true;await window.privateBattle.sendAction({type:'attack',attackerId:selected.onlineId,targetId:unit.onlineId});battleBusy=false;return}select(unit);return}if(phase!=='player'){window.privateBattleError("Your rival is still moving. You may inspect troops while you wait.");return}if(!tile||!selected||selected.team!=='player'){deselect();return}if(selected.moved||selected.acted){flashAction(selected,'move');window.privateBattleError(`${selected.name}'s movement is already used.`);return}const steps=walkDistance(selected,tile.userData.x,tile.userData.y);if(!steps||steps>classes[selected.type].move){window.privateBattleError('That destination is out of range.');return}battleBusy=true;await window.privateBattle.sendAction({type:'move',unitId:selected.onlineId,x:tile.userData.x,y:tile.userData.y});battleBusy=false}

window.startPrivateBattle=async match=>{privateReturnMission=missionIndex;privateMode=true;privateMatch=match;missionIndex=2;buildPrivateBoard(match)};
window.applyPrivateBattleUpdate=syncPrivateMatch;
window.privateBattleError=message=>{hint(message);sfx('click')};
window.privateBattleOpponentLeft=()=>{if(!privateMode)return;phase='done';ui.modal.dataset.privateShown='true';ui.modalButton.dataset.private='true';showModal('BATTLE ABANDONED','YOUR RIVAL WITHDREW','The other player left this private battlefield.','RETURN TO WAR TABLE')};
window.exitPrivateBattle=()=>{privateMode=false;privateMatch=null;privateQueuedMatch=null;privateApplying=false;ui.modalButton.dataset.private='';ui.modal.classList.add('hidden');ui.missionSelect.disabled=false;ui.mobileMissionSelect.disabled=false;missionIndex=privateReturnMission;setup()};
function routeTo(unit,targetX,targetY){const resident=occupied(targetX,targetY);if(blocked(targetX,targetY)||(resident&&resident!==unit))return null;const queue=[{x:unit.x,y:unit.y,path:[]}],seen=new Set([`${unit.x},${unit.y}`]);while(queue.length){const cell=queue.shift();if(cell.x===targetX&&cell.y===targetY)return cell.path;for(const [dx,dy] of [[-1,0],[1,0],[0,-1],[0,1]]){const x=cell.x+dx,y=cell.y+dy,key=`${x},${y}`,occupant=occupied(x,y);if(x>=0&&x<6&&y>=0&&y<6&&!seen.has(key)&&!blocked(x,y)&&(!occupant||occupant===unit)){seen.add(key);queue.push({x,y,path:[...cell.path,{x,y}]})}}}return null}
function canStrikeFrom(type,x,y,target){const dx=Math.abs(x-target.x),dy=Math.abs(y-target.y);return type==='bow'?((dx===0&&dy===2)||(dy===0&&dx===2)||(dx===1&&dy===1)):dx+dy===1}
function coverAt(x,y){return obstacles.some(o=>['tree','rock'].includes(o.type)&&Math.abs(x-o.x)+Math.abs(y-o.y)===1)}
function bestAttackRoute(unit,target){const routes=[];for(let x=0;x<6;x++)for(let y=0;y<6;y++){if(!canStrikeFrom(unit.type,x,y,target))continue;const path=routeTo(unit,x,y);if(!path)continue;const brambles=path.filter(step=>obstacles.some(o=>o.type==='bramble'&&o.x===step.x&&o.y===step.y)).length;routes.push({path,score:path.length+brambles*.8-(coverAt(x,y) ? .25 : 0)})}return routes.sort((a,b)=>a.score-b.score)[0]||null}
function enemyPlan(unit){return units.filter(u=>u.team==='player').map(target=>{const route=bestAttackRoute(unit,target);if(!route)return null;const onShrine=obstacles.some(o=>o.type==='shrine'&&o.x===target.x&&o.y===target.y);return {target,path:route.path,score:route.score+target.hp*.16-(onShrine?2:0)}}).filter(Boolean).sort((a,b)=>a.score-b.score)[0]||null}
function tutorialPatrolStep(unit,target){return [[-1,0],[1,0],[0,-1],[0,1]].map(([dx,dy])=>({x:unit.x+dx,y:unit.y+dy})).filter(p=>p.x>=0&&p.x<6&&p.y>=0&&p.y<6&&!blocked(p.x,p.y)&&!occupied(p.x,p.y)).sort((a,b)=>Math.abs(a.x-target.x)+Math.abs(a.y-target.y)-Math.abs(b.x-target.x)-Math.abs(b.y-target.y))[0]||null}
async function endTurn(){if(privateMode){if(phase!=='player'||battleBusy){window.privateBattleError("It is not your turn yet.");return}sfx('click');selected=null;hoveredTile=null;clearTiles();resetEmissive();updateUI();battleBusy=true;await window.privateBattle.sendAction({type:'end_turn'});battleBusy=false;return}if(tutorialActive()&&tutorialStep!==4&&tutorialStep!==6){tutorialReject();return}if(phase!=='player'||battleBusy)return;sfx('click');selected=null;hoveredTile=null;clearTiles();resetEmissive();updateUI();phase='enemy';hint('Enemy turn…');log('— ENEMY TURN —');tutorialAdvance('end');await wait(400);for(const e of [...units.filter(u=>u.team==='enemy')]){if(!alive(e)||phase==='done')break;if(missions[missionIndex].tutorial&&tutorialStep<4)continue;const plan=enemyPlan(e);if(!plan)continue;const step=plan.path.length?plan.path[Math.min(classes[e.type].move,plan.path.length)-1]:missions[missionIndex].tutorial?tutorialPatrolStep(e,plan.target):null;if(step){await moveUnit(e,step.x,step.y);sfx('move');if(applyTerrainEffects(e))return;if(!alive(e))continue}if(!missions[missionIndex].tutorial&&alive(e)&&alive(plan.target)&&canAttack(e,plan.target)){await attack(e,plan.target);if(phase==='done')return}}if(checkEnd())return;phase='player';units.filter(u=>u.team==='player').forEach(u=>{u.moved=false;u.acted=false});hint(missions[missionIndex].tutorial?'Continue the field drill.':'Your turn. Select a unit.');log(missions[missionIndex].tutorial?'— TRAINING TURN —':'— YOUR TURN —')}
function tileFromHits(hits){const cell=hits.map(h=>h.object.userData.cell).find(Boolean);return hits.map(h=>h.object).find(x=>x.userData.tile)||(cell&&terrainTile(cell.x,cell.y))}
canvas.addEventListener('pointermove',ev=>{if(phase!=='player'||battleBusy||!selected||selected.team!=='player'||selected.moved||selected.acted){if(hoveredTile){hoveredTile=null;paintSelection()}return}const r=canvas.getBoundingClientRect();pointer.set((ev.clientX-r.left)/r.width*2-1,-(ev.clientY-r.top)/r.height*2+1);ray.setFromCamera(pointer,camera);const tile=tileFromHits(ray.intersectObjects(board.children,true)),d=tile&&walkDistance(selected,tile.userData.x,tile.userData.y),guide=tutorialGuideTile(),next=d&&d<=classes[selected.type].move&&(!tutorialActive()||!guide||tile===guide)?tile:null;if(next===hoveredTile)return;hoveredTile=next;paintSelection();if(hoveredTile)hoveredTile.material.color.setHex(0xa7c85d)});canvas.addEventListener('pointerleave',()=>{if(hoveredTile){hoveredTile=null;paintSelection()}});
canvas.addEventListener('pointerdown',async ev=>{unlockAudio();if((phase!=='player'&&!privateMode)||battleBusy)return;const r=canvas.getBoundingClientRect();pointer.set((ev.clientX-r.left)/r.width*2-1,-(ev.clientY-r.top)/r.height*2+1);ray.setFromCamera(pointer,camera);const hits=ray.intersectObjects(board.children,true);if(privateMode){if(!hits.length){deselect();return}await handlePrivatePointer(hits);return}if(!hits.length){if(tutorialActive())tutorialReject();else deselect();return}let o=hits[0].object;while(o.parent&&o.parent!==board)o=o.parent;const unit=units.find(x=>x.mesh===o),tile=tileFromHits(hits);if(tutorialActive()){const required=tutorialUnit(),guide=tutorialGuideTile(),trainee=units.find(u=>u.name==='Trainee'),mayInspect=unit===trainee&&tutorialStep===2,mayAttack=unit===trainee&&selected&&!selected.acted&&canAttack(selected,unit)&&(tutorialStep===3&&selected.name==='Moss'&&selected.x===3&&selected.y===3||tutorialStep===8&&selected.name==='Nia'&&selected.moved),maySelect=unit&&unit.team==='player'&&unit.name===required,mayReview=unit&&unit.team==='player'&&unit.moved&&unit.acted,mayMove=tile&&guide&&tile===guide&&selected&&selected.team==='player'&&selected.name===required&&!selected.moved&&!selected.acted;if(!(mayInspect||mayAttack||maySelect||mayReview||mayMove)||(maySelect&&unit===selected&&!unit.acted)){tutorialReject();return}}if(unit){if(unit.team==='player'&&unit===selected&&!unit.acted){deselect();return}if(unit.team==='player')select(unit);else if(unit.team==='enemy'&&selected&&selected.team==='player'&&!selected.acted&&canAttack(selected,unit)){const actor=selected;await attack(actor,unit);if(alive(actor)){actor.acted=true;actor.moved=true}tutorialAdvance(actor.type==='bow'?'bow':'attack');updateUI()}else if(unit.team==='enemy'&&selected&&selected.team==='player'&&selected.acted){flashAction(selected,'attack');hint(`${selected.name}'s ATTACK ACTION is already used. End the turn to refresh it.`);sfx('click')}else if(unit.team==='enemy'&&missions[missionIndex].tutorial&&tutorialStep===3&&selected&&selected.team==='player'){hint('Out of range. Select Moss and move him to the gold tile first.');sfx('click')}else if(unit.team==='enemy')select(unit);else deselect();return}if(tile&&selected&&selected.team==='player'&&(selected.moved||selected.acted)){flashAction(selected,'move');hint(`${selected.name}'s MOVE ACTION is already used. Select a fresh ally or end the turn.`);sfx('click');return}if(tile&&selected&&selected.team==='player'&&!selected.moved&&!selected.acted){const d=walkDistance(selected,tile.userData.x,tile.userData.y);if(d&&d<=classes[selected.type].move){const mover=selected;battleBusy=true;await moveUnit(mover,tile.userData.x,tile.userData.y);const missionEnded=applyTerrainEffects(mover);battleBusy=false;if(missionEnded||!alive(mover))return;mover.moved=true;tutorialAdvance('move');sfx('move');if(missions[missionIndex].tutorial&&tutorialStep===8&&mover.name!=='Nia'){deselect();hint('Select Nia to learn bow mechanics.')}else select(mover);return}}if(tutorialActive())tutorialReject();else deselect()});
ui.endTurn.onclick=endTurn;ui.endTurnMobile.onclick=endTurn;ui.tutorial.onclick=e=>{const toggle=e.target.closest('.tutorial-toggle');if(toggle){sfx('click');const dismissed=ui.tutorial.classList.toggle('mobile-dismissed');toggle.textContent=dismissed?'OPEN':'HIDE';toggle.setAttribute('aria-label',dismissed?'Open tutorial panel':'Hide tutorial panel');toggle.setAttribute('aria-expanded',String(!dismissed))}};ui.playTutorial.onclick=()=>{sfx('click');ui.startChoice.classList.add('hidden');missionIndex=0;setup()};ui.skipTutorial.onclick=()=>{sfx('click');ui.startChoice.classList.add('hidden');missionIndex=1;setup()};document.querySelector('#sound-button').onclick=e=>{sound=!sound;if(sound){unlockAudio();sfx('click')}else stopMusic();e.target.textContent=`SOUND: ${sound?'ON':'OFF'}`};ui.battleButton.onclick=dismissBattle;ui.missionSelect.onchange=e=>{if(privateMode)return;missionIndex=Number(e.target.value);sfx('click');setup()};ui.mobileMissionSelect.onchange=e=>{if(privateMode)return;missionIndex=Number(e.target.value);sfx('click');setup()};document.addEventListener('keydown',e=>{if(e.key==='Escape')dismissBattle();if(e.code==='Space'){e.preventDefault();endTurn()}if(e.key.toLowerCase()==='r'){sfx('click');if(privateMode)window.privateBattleError('Private battles cannot be restarted.');else setup()}});ui.modalButton.onclick=()=>{sfx('click');if(ui.modalButton.dataset.private==='true'){window.privateBattle.leave();return}ui.modal.classList.add('hidden');if(!units.some(u=>u.team==='player'))setup();else if(missions[missionIndex].boss){missionIndex=1;setup()}else{missionIndex=Math.min(missionIndex+1,missions.length-1);setup()}};
function resize(){const w=wrap.clientWidth,h=wrap.clientHeight;renderer.setSize(w,h,false);const a=w/h;camera.left=-6*a;camera.right=6*a;camera.top=6;camera.bottom=-6;camera.updateProjectionMatrix()}addEventListener('resize',resize);resize();setup();renderer.setAnimationLoop(time=>{const t=time*.001;ambience.forEach(item=>{if(item.kind==='mist'){item.mesh.position.y=item.baseY+Math.sin(t+item.phase)*.08;item.mesh.position.x=item.baseX+Math.sin(t*.35+item.phase)*.12}if(item.kind==='ember'){item.mesh.position.y=item.baseY+Math.sin(t*1.8+item.phase)*.18;item.mesh.position.x=item.baseX+Math.cos(t+item.phase)*.08}if(item.kind==='flame'){const flicker=1+Math.sin(t*11+item.phase)*.14;item.mesh.scale.set(flicker,1+Math.sin(t*14+item.phase)*.16,flicker)}});if(tutorialMarker){tutorialMarker.rotation.y=t*2.4;tutorialMarker.position.y=tutorialMarker.userData.baseY+Math.sin(t*3.4)*.08}renderer.render(scene,camera)});
